    state.logs[today] = todayLog;

    await supabaseClient
      .from('user_data')
      .update({ content: state, updated_at: new Date().toISOString() })
      .eq('user_id', currentUserId);

    renderHabits(state.habits, todayLog.completedHabitIds);
    syncStatus.innerText = 'SAVED';
  } catch (err) {
